-- 0106_edited_tables_import.sql
  -- Applies the reviewed edited-tables.xlsx import (session plan rulings #1-#3 + amendments).
  -- Idempotent: guarded UPDATEs no-op when already applied or when rows are absent (stale dev).
  -- Apply with: psql "$PROD_DATABASE_URL" -1 -v ON_ERROR_STOP=1 -f lib/db/migrations/0106_edited_tables_import.sql
  -- (dev: psql "$DATABASE_URL" -1 -v ON_ERROR_STOP=1 -f ...)
  -- PREREQ: Publish must have shipped the 2026-07 schema changes (reimbursement enum, new columns, charters table) FIRST.
  -- NO BEGIN/COMMIT here: psql -1 wraps the whole file in one transaction.
  
-- ===== Section 1: seed rows (idempotent) =====
