-- ===== Section 3: Omidyar merge-loser PA consolidation (Amendment #3) =====
DO $om$
  DECLARE bad int;
  BEGIN
    IF EXISTS (SELECT 1 FROM payment_applications WHERE id IN ('8a5b3cbf-885f-4aeb-bf18-f319445b5404','9ca421e1-631a-41f8-85ac-3e45fda6c98c')) THEN
      -- each loser gift must hold EXACTLY its one known 500k counted quickbooks PA on the expected deposit, and nothing else
      SELECT count(*) INTO bad FROM payment_applications pa
        WHERE pa.gift_id IN ('recRfzkuB6wB6QlRr','recgLkgoCHL05n7mZ')
          AND NOT (pa.id IN ('8a5b3cbf-885f-4aeb-bf18-f319445b5404','9ca421e1-631a-41f8-85ac-3e45fda6c98c')
                   AND pa.amount_applied = 500000.00 AND pa.link_role='counted' AND pa.evidence_source='quickbooks'
                   AND pa.payment_id IN ('4Jn9XEMRrTWvBKKRiMU4f','4svk9IxogJIjkx65k097w'));
      IF bad > 0 THEN RAISE EXCEPTION 'Omidyar pre-flight: % unexpected payment_applications rows on loser gifts', bad; END IF;
      SELECT count(*) INTO bad FROM staged_payments sp
        WHERE sp.matched_gift_id IN ('recRfzkuB6wB6QlRr','recgLkgoCHL05n7mZ')
           OR sp.created_gift_id IN ('recRfzkuB6wB6QlRr','recgLkgoCHL05n7mZ')
           OR sp.group_reconciled_gift_id IN ('recRfzkuB6wB6QlRr','recgLkgoCHL05n7mZ');
      IF bad > 0 THEN RAISE EXCEPTION 'Omidyar pre-flight: % staged_payments still reference loser gifts', bad; END IF;
      SELECT count(*) INTO bad FROM stripe_staged_charges ssc
        WHERE ssc.matched_gift_id IN ('recRfzkuB6wB6QlRr','recgLkgoCHL05n7mZ')
           OR ssc.created_gift_id IN ('recRfzkuB6wB6QlRr','recgLkgoCHL05n7mZ');
      IF bad > 0 THEN RAISE EXCEPTION 'Omidyar pre-flight: % stripe_staged_charges still reference loser gifts', bad; END IF;
    ELSE
      RAISE NOTICE 'Omidyar loser PA rows absent (stale dev or already consolidated) - skipping shape assert';
    END IF;
  END $om$;
DELETE FROM payment_applications WHERE id='8a5b3cbf-885f-4aeb-bf18-f319445b5404' AND gift_id='recRfzkuB6wB6QlRr' AND amount_applied=500000.00 AND link_role='counted';
UPDATE payment_applications SET amount_applied=1000000.00, note=coalesce(note || ' | ', '') || 'import edited-tables 2026-07: absorbed 500000.00 counted row from merged loser recRfzkuB6wB6QlRr', updated_at=now() WHERE id='cfde97df-e177-4d34-a36c-a0aab14abb4b' AND gift_id='reckelLlxExPB5C6e' AND amount_applied=500000.00;
DELETE FROM payment_applications WHERE id='9ca421e1-631a-41f8-85ac-3e45fda6c98c' AND gift_id='recgLkgoCHL05n7mZ' AND amount_applied=500000.00 AND link_role='counted';
UPDATE payment_applications SET amount_applied=1000000.00, note=coalesce(note || ' | ', '') || 'import edited-tables 2026-07: absorbed 500000.00 counted row from merged loser recgLkgoCHL05n7mZ', updated_at=now() WHERE id='fa987394-cbaf-46c7-a829-68616733c907' AND gift_id='recAjHdhK9R6eEAi1' AND amount_applied=500000.00;

