DO $ar$
  DECLARE bad int;
  BEGIN
    SELECT count(*) INTO bad FROM gift_allocations WHERE gift_id IN ('recRfzkuB6wB6QlRr','recgLkgoCHL05n7mZ');
    IF bad > 0 THEN RAISE EXCEPTION 'archive pre-flight: % allocations still on Omidyar loser gifts', bad; END IF;
  END $ar$;
