-- ===== Section 11: off-books entity re-points (plan #26; makes giftPaymentSummary derive off-books/exempt) =====
-- 3 direct-to-school gifts' allocations -> entity direct_to_school; RWJF recc9rR57VNo1tHBm (incl. merged-in alloc) -> wildflower_foundation_tsne.
UPDATE gift_allocations SET entity_id='direct_to_school', updated_at=now()
  WHERE gift_id IN ('recfC2SCEY643qShl','recQE2y1hKmifyDPj','recsy6YfVFoHcDOmQ')
    AND entity_id IS DISTINCT FROM 'direct_to_school'
    AND EXISTS (SELECT 1 FROM entities WHERE id='direct_to_school');
UPDATE gift_allocations SET entity_id='wildflower_foundation_tsne', updated_at=now()
  WHERE gift_id = 'recc9rR57VNo1tHBm'
    AND entity_id IS DISTINCT FROM 'wildflower_foundation_tsne'
    AND EXISTS (SELECT 1 FROM entities WHERE id='wildflower_foundation_tsne');
